def find_receipt_pair(amounts, target):
    seen = {}
    for i, amount in enumerate(amounts):
        complement = target - amount
        if complement in seen:
            return [seen[complement], i]
        seen[amount] = i
    return []

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_decimals(self):
        self.assertEqual(find_receipt_pair([12.50, 7.25, 3.75, 9.00], 16.25), [0, 2])

    def test_basic_integers(self):
        self.assertEqual(find_receipt_pair([5, 10, 15, 20], 25), [1, 2])

    def test_no_pair(self):
        self.assertEqual(find_receipt_pair([1, 2, 3], 10), [])

    def test_hidden_two_elements(self):
        self.assertEqual(find_receipt_pair([100, 200], 300), [0, 1])

    def test_hidden_duplicate_values(self):
        self.assertEqual(find_receipt_pair([1, 1], 2), [0, 1])

    def test_hidden_single_element(self):
        self.assertEqual(find_receipt_pair([5], 5), [])

    def test_hidden_empty_list(self):
        self.assertEqual(find_receipt_pair([], 0), [])

    def test_hidden_pair_at_end(self):
        self.assertEqual(find_receipt_pair([3.50, 8.00, 4.50, 6.50, 1.50], 10.0), [0, 3])

    def test_hidden_larger_list(self):
        amounts = list(range(1, 101))
        # 1 + 100 = 101, but scanning: at i=99 (value 100), complement=1, seen at index 0
        self.assertEqual(find_receipt_pair(amounts, 101), [0, 99])

    def test_hidden_no_self_pair(self):
        # [5, 3, 7] target=10: 5+3=8, 5+7=12, 3+7=10 -> [1, 2]
        self.assertEqual(find_receipt_pair([5, 3, 7], 10), [1, 2])

if __name__ == '__main__':
    unittest.main()
